var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"서윤 양의 보고는 이상입니다.","JPN":"シズカさんの報告は以上です。","ENG":"That concludes Seo Yoon's report.","TWN":"以上就是徐芸的報告。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"결국 소원구슬은 회수하지 못했군요.","JPN":"結局願い玉は回収できなかったようですね。","ENG":"In a nutshell, we failed to collect the Wishing Ball.","TWN":"結果還是沒能收回許願珠啊。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"다른 사람 손에 들어가는 것은 막았으니, 일단은 절반의 성공이라고 봐야겠죠.","JPN":"他の人の手に渡ることは防いだので、一旦は半分成功ということで。","ENG":"But we could call it a half success, since we did prevent it from falling into someone else's hands.","TWN":"成功地阻止了許願珠落入他人之手，也可以說是成功了一半。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그거 다행이군.","JPN":"それは良かった。","ENG":"I'm glad to hear that.","TWN":"那就好。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 소원구슬은 힘이 유출되지 않게 전용 케이스에 보관됐을 텐데......","JPN":"しかし、願い玉は力が流出しないよう専用ケースに保管していたはずなのに……","ENG":"I assume the Wishing Ball was stored in a special case to prevent power leakage.","TWN":"不過為了防止力量外泄，許願珠應該保管在專用盒子裡吧……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"어떻게 침식체들이 나타난 거지?","JPN":"どうして侵食体が現れたのだろう？","ENG":"How did it manage to attract the C.O.s?","TWN":"怎麼會出現侵蝕體呢？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"확인해 보니 홍보 담당자가 운동회 중간에 케이스를 빼서 버렸다더군요.","JPN":"確認したところ、広報担当者が運動会の途中でケースを外して捨てたそうです。","ENG":"It turned out the PR manager removed and discarded the case halfway through the Field Day.","TWN":"徐芸調查以後發現，宣傳負責人在運動會期間換掉了盒子。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"구슬의 반짝이는 모습을 보여주는 게 홍보에 더 도움이 된다면서 말이죠.","JPN":"玉の輝きを見せたほうが宣伝に役に立つと。","ENG":"He thought showing its glowing radiance would help advertise the occasion more effectively.","TWN":"他說露出珠子發光的樣子會對宣傳有幫助。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"......누군지 몰라도 안전 불감증이라는 건 확실한 것 같군.","JPN":"……誰なのかは知らないが、危機管理能力が足りないな。","ENG":"Whoever he is, he needs to learn about safety.","TWN":"……雖然不知道是誰，真是缺乏安全意識啊。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래서 그 뒤는 어떻게 됐지?","JPN":"それで、その後はどうなったんだ？","ENG":"What happened afterward?","TWN":"那後來怎麼樣了？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"소원구슬이 가짜라는 소문이 나서 학생들......","JPN":"願い玉が偽物だという噂が流れて、生徒たちが……","ENG":"A rumor spread that the Wishing Ball was a fake, and the students complained about it.","TWN":"都在傳許願珠是假的，學生們……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"특히 나이엘이라는 친구가 크게 항의를 했다고 합니다.","JPN":"特にナイエルという子が激しく抗議したそうです。","ENG":"Especially the one named Naielle.","TWN":"特別是那個叫奈爾的學生，提出了嚴重的抗議。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하지만 아티팩트를 제공한 브라우니라는 선생은 이미 사라져 버렸다더군요.","JPN":"しかし、アーティファクトを提供したブラウニー先生という方はすでに消えてしまったそうです。","ENG":"But the teacher, Brownie, who provided the Artifact had already disappeared.","TWN":"不過聽說提供人造神器的布朗尼老師已經消失了。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이런 쪽지를 남겨 두고 말이죠.","JPN":"こんなメモを残して、です。","ENG":"She left this note.","TWN":"她留下了這樣的紙條。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"안녕! 학생 여러분!","JPN":"こんにちは、生徒のみなさん！","ENG":"Hello, students!","TWN":"大家好！各位同學！"},"stage":{"bg":"CLASS","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"선생님은 여러분을 너~무 좋아하지만, 아쉽게도 한동안 못 보게 될 것 같아.","JPN":"先生はみんなのことが大好きだけど、残念ながらしばらく会えなくなりそうです。","ENG":"I love you guys very much, but I'll have to leave you for a while.","TWN":"老師很~喜歡你們，不過很可惜，老師有一段時間都不能跟你們見面了。"},"stage":{"bg":"CLASS","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"왜냐하면 이면세계에 굉장한 유적이 발견되었다고 하거든!","JPN":"なぜなら、裏世界でとんでもない遺跡が発見されたらしいの！","ENG":"An incredible site has been discovered on the Counterside!","TWN":"因為我聽說異界發現了偉大的遺跡！"},"stage":{"bg":"CLASS","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"그래서 다른 얼치기들이 선수를 치기 전에......","JPN":"それで他の人に先手を打たれる前に……","ENG":"I'd better go before some idiots beat me to it—","TWN":"所以，在其他半吊子先下手之前……"},"stage":{"bg":"CLASS","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"아, 아니, 아티팩트의 안전한 보존을 위해 선생님도 잠깐 그곳에 다녀오기로 했어!","JPN":"い、いや、アーティファクトの安全保存のために、先生もしばらくそこに行くことにしたよ！","ENG":"I mean, I've decided to go to preserve the Artifacts that might be found there.","TWN":"不，不是，為了人造神器的安全保存，老師也決定去去查看一下！"},"stage":{"bg":"CLASS","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"31번의 미스터리라거나, 소원구슬이 불량품이라거나 하는 사소한 문제가 남아있긴 하지만......","JPN":"出席番号31番のミステリーとか、願い玉が不良品とか、些細な問題が残っているけど……","ENG":"I'm sorry I'm leaving behind a couple of minor issues (namely, the mystery of Number Thirty-one and the Wishing Ball that may or may not be a defect),","TWN":"雖然還未找出神秘的31號，還有許願珠是不良品的一些小問題……"},"stage":{"bg":"CLASS","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"그런 건 내가 없더라도 학생 여러분들이 잘 해결할 수 있을 거라고 생각해!","JPN":"そんなことは私がいなくてもみんなでうまく解決できると思う！","ENG":"but I'm sure you guys can solve them without me.","TWN":"但我相信，即使沒有我，你們自己也能很好地解決這些問題！"},"stage":{"bg":"CLASS","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":null,"text":{"KOREA":"선생님은 여러분들을 믿고 있어요! 아자!","JPN":"先生はみなさんのことを信じています！　頑張ってね！","ENG":"I believe in you. You can do it!","TWN":"老師相信大家！加油！"},"stage":{"bg":"CLASS","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":null,"text":{"KOREA":"이번에도 재미있는 모험담을 잔~뜩 가져와서 보여줄게! 꼭 약속! 도장 쾅!","JPN":"今度面白い冒険話をたくさん持ち帰って聞かせてあげる！　約束ね♪　ゆびきりげんまん♪","ENG":"I'll come back with lots and lots of exciting adventure stories to tell you. I promise.","TWN":"這次我也會給大家帶回來很~多有趣的冒險故事的！我保證！蓋章 哐！"},"stage":{"bg":"CLASS","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":null,"text":{"KOREA":"그럼, 선생님이 돌아올 때까지 아디오스~","JPN":"じゃあ、先生が帰ってくるまでアディオスだよ～！","ENG":"Now, stay safe until I come back. Adios!","TWN":"等老師回來哦，拜拜~"},"stage":{"bg":"CLASS","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그 친구, 아직도 깨닫지 못한 모양이군.","JPN":"あいつはまだ気づいていないようだな。","ENG":"She still hasn't realized, has she?","TWN":"那個人，看來還沒有意識到啊。"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"진정한 최고의 탐험가는 오직 <color=#ffd34c>인디애나 GAP</color>뿐이라는 것을......","JPN":"本物の最高探検家は<color=#ffd34c>インディアナ-甲-</color>だけだということを……","ENG":"That the world's greatest explorer is not her, but <color=#ffd34c>Indiana G.A.P.</color>","TWN":"真正的頂級探險家只有<color=#ffd34c>印第安納GAP</color>……"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아무래도 다시 한 번 내가 직접 나서야겠어.","JPN":"どうやら私の出番が来たようだ。","ENG":"I'll have to go prove it to her again.","TWN":"看來我得親自出馬才行。"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"안 됩니다. 사장님은 당분간 외출 금지예요.","JPN":"だめです。社長はしばらく外出禁止です。","ENG":"No. You're grounded.","TWN":"不行，老闆你暫時禁止外出。"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하, 하지만 이건 탐험가들끼리의 자존심이 걸린 싸움인데......","JPN":"し、しかしこれは探検家同士のプライドがかかった戦いなのだが……","ENG":"B-but my pride as an explorer is at stake.","TWN":"這，這可是探險家之間的自尊心之戰……"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그런 것보다 경영자로서의 자존심도 지켜 보시면 어떨까요?","JPN":"そんなことより経営者としてのプライドも守ってみてはいかがでしょうか？","ENG":"Why don't you focus on your pride as a business owner for now?","TWN":"比起那個，你先守住作為管理者的自尊心怎麼樣？"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"어차피 사장님의 카드도 다 정지시켜 놓았습니다.","JPN":"それと社長のクレジットカードも全部停止させておきました。","ENG":"I've frozen your credit cards, anyway.","TWN":"反正老闆的卡也全都停了。"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"무일푼으로 가실 생각이라면 마음대로 하시죠.","JPN":"無一文で行くつもりなら勝手にしてください。","ENG":"If you think you can do it without money, go ahead.","TWN":"如果你想兩手空空地去，那隨便你。"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"......자네는 볼 때마다 대단하군.","JPN":"君は本当にすごいな。","ENG":"You never fail to amaze me.","TWN":"……你真是不斷刷新我的三觀啊。"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"마왕들도 날 이렇게 꼼짝 못하게 만들진 못했는데......","JPN":"魔王たちも私をここまで追い詰めることはできなかったのだが。","ENG":"Even the Demon Lords couldn't make me feel so helpless.","TWN":"即使是魔王也沒法讓我如此不能動彈啊……"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"어쨌거나 일은 그렇게 마무리 되었습니다.","JPN":"とりあえず、この件はこれで一段落しました。","ENG":"Anyway, the case is solved.","TWN":"總之，事情就這樣了。"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하지만 아직 설명이 되지 않는 부분들이 많군요.","JPN":"しかしまだ理解しがたい部分が多いですね。","ENG":"But many questions remain unanswered.","TWN":"不過還有很多無法解釋的部分。"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"마지막 순간에 나타난 대형 침식체가 흔적도 없이 사라져 버린 일이나......","JPN":"最後の瞬間に現れた大型侵食体が跡形もなく消えてしまったことや……","ENG":"Like that gigantic C.O. that showed up at the end and disappeared without a trace.","TWN":"最後一瞬間出現的大型侵蝕體消失得無影無蹤的事……"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"소원 구슬이 갑작스럽게 힘을 잃어 버린 것도 말이죠.","JPN":"願い玉が急に力を無くしてしまったことです。","ENG":"Or the Wishing Ball's sudden loss of power.","TWN":"還有許願珠突然失去力量的事。"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아무래도 진실을 알아내려면 조금 더 조사가 필요할 것 같습니다.","JPN":"どうやら真実を突き止めるにはもう少し調査が必要だと思います。","ENG":"I'll have to look further to get to the bottom of this case.","TWN":"看來要想查出真相，還需要做進一步的調查。"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아, 그럴 필요는 없네.","JPN":"ああ、その必要はない。","ENG":"Oh, that won't be necessary.","TWN":"啊，沒那個必要。"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"보호자로 파견했던 알렉스 부전대장이 추가 보고서를 가져왔거든.","JPN":"保護者として派遣したアレックス副戦隊長が追加報告書を持ってきたんだ。","ENG":"Deputy Commander Alex, who was sent as a chaperone, has submitted an additional report.","TWN":"作為監護人派遣的雅蕾克絲副隊長拿來了補充報告。"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"뭐라고요? 왜 전 그 사실을 모르고 있었던 거죠?","JPN":"何ですって？　なぜ私にその事を知らせなかったのですか？","ENG":"Pardon? Why wasn't I informed of it?","TWN":"你說什麼？我怎麼不知道？"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그야 나도 방금 받은 자료니까.","JPN":"私もさっきもらったばかりの資料だからな。","ENG":"Because I just received it now.","TWN":"我也是剛收到的資料。"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이리 와서 앉게나. 같이 보도록 하지.","JPN":"まあまあ座りなさい。一緒に読んでみよう。","ENG":"Come here and have a seat. We'll read it together.","TWN":"過來坐下一起看吧。"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};